import json
import logging
import boto3

# IAM Role with S3 Read/Write, SNS Publish, CloudWatch Logs permissions
# role:arn:aws:iam::123456789012:role/lambda_role

def lambda_handler(event, context):
    # Get S3 event information
    bucket = event['Records'][0]['s3']['bucket']['name']
    key = event['Records'][0]['s3']['object']['key']

    # Create S3 client
    s3_client = boto3.client('s3')

    # Download image from S3
    image_data = s3_client.get_object(Bucket=bucket, Key=key)['Body'].read()

    # Perform image processing here (e.g., resizing, filtering)

    # Upload processed image to S3
    s3_client.put_object(Bucket=bucket, Key='processed/' + key, Body=image_data)

    # Send notification via SNS
    sns_client = boto3.client('sns')
    sns_client.publish(TopicArn='arn:aws:sns:us-east-1:123456789012:image_processing_topic', Message='Image processed successfully.')

    # Log to CloudWatch
    logger = logging.getLogger()
    logger.info('Image processed successfully.')

    return {
        'statusCode': 200,
        'body': json.dumps('Image processed successfully.')
    }